import redis
from redis import StrictRedis

# Set up a Redis cluster client using the redis-py library
redis_client = StrictRedis(host='localhost', port=6379, db=0)

# Use the setex() method to store sensitive user data with an appropriate TTL value
redis_client.setex('session_token', 3600, 'secret_session_token')
redis_client.setex('api_key', 86400, 'secret_api_key')

# Use the get() method to retrieve stored data
session_token = redis_client.get('session_token')
api_key = redis_client.get('api_key')

# Use platform-appropriate secure techniques to prevent unencrypted connections
redis_client.use_ssl(True)
redis_client.use_tls(True)